window.currentLectureFilter = 'all';
window.currentPlayingLectureAudio = null; 
window.currentPlayingLectureBtn = null;
window.currentPlayingGlobalId = null;     

function formatLectureTime(seconds) {
    if (isNaN(seconds) || seconds === Infinity || seconds < 0) return "0:00";
    const m = Math.floor(seconds / 60);
    const s = Math.floor(seconds % 60);
    return `${m}:${s < 10 ? '0' : ''}${s}`;
}

async function getCachedFileSizeMB(url) {
    try {
        if (!('caches' in window)) return null;
        const cache = await caches.open('athr-audio-cache-v1');
        const match = await cache.match(url);
        if (!match) return null;
        const blob = await match.blob();
        return (blob.size / (1024 * 1024)).toFixed(1);
    } catch (e) { return null; }
}

function ensureGlobalAudioEngine() {
    let audio = document.getElementById('athrGlobalLectureEngine');
    if (!audio) {
        audio = document.createElement('audio');
        audio.id = 'athrGlobalLectureEngine';
        audio.style.display = 'none';
        document.body.appendChild(audio);

        audio.onloadedmetadata = () => {
            const id = window.currentPlayingGlobalId;
            const totalEl = document.getElementById('lectureTotalTime_' + id);
            if (totalEl && audio.duration) {
                totalEl.textContent = formatLectureTime(audio.duration);
            }
        };

        audio.ontimeupdate = () => {
            const id = window.currentPlayingGlobalId;
            const seek = document.getElementById('lectureSeek_' + id);
            const curEl = document.getElementById('lectureCurTime_' + id);
            if (!seek || !curEl) return;
            if (audio.duration > 0) {
                seek.value = (audio.currentTime / audio.duration) * 100;
                curEl.textContent = formatLectureTime(audio.currentTime);
            }
        };

        audio.onended = () => {
            const id = window.currentPlayingGlobalId;
            const btn = document.getElementById('lectureBtn_' + id);
            if (btn) btn.textContent = '▶';
            window.currentPlayingLectureAudio = null;
            window.currentPlayingLectureBtn = null;
            window.currentPlayingGlobalId = null;
        };
    }
    return audio;
}

function renderLectures() {
    const listEl = document.getElementById('lecturesList');
    if (!listEl) return;

    // 1. بناء المربع الذهبي لاسم الشيخ والدورة
    let sheikhBannerHtml = "";
    const info = window.sheikhsInfoData ? window.sheikhsInfoData[window.currentLectureFilter] : null;

    if (info) {
        sheikhBannerHtml = `
        <div style="background: linear-gradient(135deg, rgba(212,175,55,0.15) 0%, rgba(20,30,22,0.85) 100%); border: 1px solid var(--gold); border-right: 5px solid var(--gold); border-radius: 14px; padding: 16px; margin-bottom: 15px; direction: rtl; text-align: right; box-shadow: 0 6px 20px rgba(0,0,0,0.3);">
            <div style="display: flex; align-items: center; justify-content: space-between; margin-bottom: 6px;">
                <div style="display: flex; align-items: center; gap: 8px;">
                    <span style="font-size: 24px;">${info.icon}</span>
                    <strong style="color: var(--gold); font-family: 'Amiri', serif; font-size: 17px;">${info.title}</strong>
                </div>
                <span style="background: var(--gold); color: #111; font-size: 10px; font-weight: bold; padding: 3px 10px; border-radius: 12px;">دورة معتمدة</span>
            </div>
            <div style="color: #fff; font-size: 14px; font-weight: bold; font-family: 'Amiri', serif; margin-bottom: 6px;">
                <span style="color: var(--gold);">👳 الملقي والشارح:</span> ${info.sheikh}
            </div>
            <p style="color: var(--text2, #ccc); font-size: 12px; margin: 0; line-height: 1.6;">${info.desc}</p>
        </div>`;
    }

    // 2. شريط البحث السريع والذكي (فقط لقسم التفسير والدورات الضخمة)
    let searchBarHtml = "";
    if (window.currentLectureFilter === 'تفسير القرآن الكريم' || window.currentLectureFilter === 'all') {
        searchBarHtml = `
        <div style="margin-bottom: 15px; direction: rtl;">
            <input type="text" id="lectureSearchInput" oninput="window.filterLecturesBySearch(this.value)" placeholder="🔍 ابحث باسم السورة أو الدرس (مثلاً: البقرة، يوسف، الكهف)..." style="width: 100%; padding: 12px 16px; border-radius: 12px; border: 1px solid var(--gold); background: var(--card); color: var(--text); font-family: 'Amiri', serif; font-size: 14px; box-sizing: border-box; box-shadow: 0 4px 10px rgba(0,0,0,0.2);" />
        </div>`;
    }

    let filtered = window.currentLectureFilter === 'all'
        ? [...window.lecturesData]
        : window.lecturesData.filter(l => l.category === window.currentLectureFilter);

    // تطبيق فلتر الكلمة المكتوبة في البحث إن وجدت
    if (window.lectureSearchQuery && window.lectureSearchInputText) {
        const q = window.lectureSearchInputText.trim().toLowerCase();
        if (q !== "") {
            filtered = filtered.filter(l => l.title.toLowerCase().includes(q));
        }
    }

    const pinnedList = JSON.parse(localStorage.getItem('pinned_lectures') || '[]');
    filtered.sort((a, b) => {
        const aPinned = pinnedList.includes(a.title) ? 1 : 0;
        const bPinned = pinnedList.includes(b.title) ? 1 : 0;
        return bPinned - aPinned;
    });

    const cardsHtml = filtered.map((lecture) => {
        const realIndex = window.lecturesData.indexOf(lecture);
        const isPinned = pinnedList.includes(lecture.title);
        const isVideo = lecture.type === 'video';
        const isThisPlaying = window.currentPlayingGlobalId === realIndex && window.currentPlayingLectureAudio && !window.currentPlayingLectureAudio.paused;

        return `
        <div style="background: var(--card); border-radius: 16px; padding: 14px; border: 1px solid var(--border); direction: rtl; margin-bottom:12px; display:flex; flex-direction:column; gap:10px;">
          <div style="display:flex; align-items:center; justify-content:space-between; gap:10px;">
            <div style="display:flex; align-items:center; gap:8px; flex:1;">
              <button onclick="window.togglePinLecture('${lecture.title}')" style="background:transparent; border:none; color:${isPinned ? 'var(--gold)' : 'var(--text2)'}; font-size:16px; cursor:pointer; padding:0; margin-left:4px;">${isPinned ? '📌' : '📍'}</button>
              <span style="font-family:'Amiri',serif; font-size:15px; color:var(--text); line-height:1.6;">${isVideo ? '🎥 ' : ''}${lecture.title}</span>
            </div>
            
            ${isVideo ? `
                <div style="display:flex; align-items:center; gap:6px; flex-shrink:0;">
                    <button onclick="window.openAthrVideoModal('${lecture.title}', '${lecture.src}')" style="background:var(--gold); color:#111; border:none; padding:6px 12px; border-radius:20px; font-weight:bold; font-size:12px; cursor:pointer;">🎬 مشاهدة</button>
                    <div id="lectureDlRing_${realIndex}" onclick="window.startLectureDownloadRing(${realIndex})" style="width:32px; height:32px; display:flex; align-items:center; justify-content:center; cursor:pointer; background:var(--bg2); color:var(--gold); border:1px solid var(--border); border-radius:50%; font-size:12px;">⬇️</div>
                </div>
            ` : `
                <button class="play-btn" id="lectureBtn_${realIndex}" onclick="window.toggleLectureAudio(${realIndex})" style="background:var(--gold); color:#111; border:none; width:34px; height:34px; border-radius:50%; font-size:14px; cursor:pointer; display:flex; align-items:center; justify-content:center; flex-shrink:0;">${isThisPlaying ? '⏸' : '▶'}</button>
                <div id="lectureDlRing_${realIndex}" onclick="window.startLectureDownloadRing(${realIndex})" style="width:34px; height:34px; flex-shrink:0; display:flex; align-items:center; justify-content:center; cursor:pointer; background:var(--bg2); color:var(--gold); border:1px solid var(--border); border-radius:50%;">⬇️</div> 
            `}
          </div>

          <div id="lectureDlStatus_${realIndex}" style="font-size:10px; color:var(--gold); margin-top:2px; text-align:center;"></div>

          ${!isVideo ? `
          <div style="margin-top:6px; width:100%;">
            <input type="range" id="lectureSeek_${realIndex}" value="0" min="0" max="100" step="0.1" oninput="window.seekLectureAudio(${realIndex}, this.value)" style="width:100%; accent-color:var(--gold); cursor:pointer; height:4px; background:rgba(255,255,255,0.2); outline:none; border-radius:2px;">
            <div style="display:flex; justify-content:space-between; font-size:11px; color:var(--text2); direction:ltr; margin-top:4px; font-family:monospace;">
              <span id="lectureCurTime_${realIndex}">0:00</span>
              <span id="lectureTotalTime_${realIndex}">--:--</span>
            </div>
          </div>
          ` : ''}
        </div>`;
    }).join('');

    listEl.innerHTML = sheikhBannerHtml + searchBarHtml + cardsHtml;
    setTimeout(markDownloadedLectures, 150);
}

// دالة الفلترة بالبحث المباشر
window.filterLecturesBySearch = function(query) {
    window.lectureSearchQuery = true;
    window.lectureSearchInputText = query;
    renderLectures();
    const input = document.getElementById('lectureSearchInput');
    if (input) {
        input.focus();
        input.value = query;
    }
};

window.togglePinLecture = function(title) {
    let pinned = JSON.parse(localStorage.getItem('pinned_lectures') || '[]');
    if (pinned.includes(title)) pinned = pinned.filter(t => t !== title);
    else pinned.push(title);
    localStorage.setItem('pinned_lectures', JSON.stringify(pinned));
    renderLectures();
};

window.toggleLectureAudio = function(index) {
    const audio = ensureGlobalAudioEngine();
    const btn = document.getElementById('lectureBtn_' + index);
    if (!btn) return;

    const lecture = window.lecturesData[index];
    if (!lecture) return;

    if (window.currentPlayingGlobalId !== index) {
        if (window.currentPlayingGlobalId !== null) {
            const oldBtn = document.getElementById('lectureBtn_' + window.currentPlayingGlobalId);
            if (oldBtn) oldBtn.textContent = '▶';
        }
        
        audio.src = lecture.src;
        audio.load(); 
        window.currentPlayingGlobalId = index;
        window.currentPlayingLectureAudio = audio;
        window.currentPlayingLectureBtn = btn;
    }

    if (audio.paused) {
        audio.play().then(() => {
            btn.textContent = '⏸';
        }).catch(err => {
            setTimeout(() => { audio.play(); btn.textContent = '⏸'; }, 150);
        });
    } else {
        audio.pause();
        btn.textContent = '▶';
    }
};

window.seekLectureAudio = function(index, value) {
    const audio = window.currentPlayingLectureAudio;
    if (index === window.currentPlayingGlobalId && audio && audio.duration) {
        audio.currentTime = (value / 100) * audio.duration;
    }
};

window.startLectureDownloadRing = function(index) {
    const lecture = window.lecturesData[index];
    if (!lecture) return;
    if (typeof downloadWithProgress === 'function') {
        downloadWithProgress(lecture.src, 'lectureDlRing_' + index);
    } else {
        window.downloadLectureAudio(index);
    }
};

window.downloadLectureAudio = function(index) {
    const lecture = window.lecturesData[index];
    const statusEl = document.getElementById('lectureDlStatus_' + index);
    if (!lecture || !navigator.serviceWorker.controller) return;
    
    if (statusEl) statusEl.textContent = '⏳ جاري بدء التنزيل في الخلفية...';
    
    navigator.serviceWorker.controller.postMessage({ 
        type: 'CACHE_AUDIO_URL', 
        url: lecture.src, 
        label: 'lecture_' + index 
    });
};

navigator.serviceWorker.addEventListener('message', (event) => {
    const d = event.data;
    if (!d || !d.label || !d.label.startsWith('lecture_')) return;
    
    const idx = parseInt(d.label.replace('lecture_', ''));
    if (isNaN(idx) || !window.lecturesData[idx]) return;
    
    const lecture = window.lecturesData[idx];
    const statusEl = document.getElementById('lectureDlStatus_' + idx);
    const ringBtn = document.getElementById('lectureDlRing_' + idx);
    
    if (d.type === 'AUDIO_CACHED') {
        getCachedFileSizeMB(lecture.src).then(size => {
            if (statusEl) statusEl.textContent = size ? `✅ جاهز أوفلاين (${size} MB)` : '✅ جاهز أوفلاين';
        });
        if (ringBtn) {
            ringBtn.textContent = '✅';
            ringBtn.style.background = 'rgba(76,175,80,0.15)';
            ringBtn.style.borderColor = '#4caf50';
            ringBtn.style.color = '#4caf50';
        }
    }
});

async function markDownloadedLectures() {
    if (!('caches' in window)) return;
    try {
        const cache = await caches.open('athr-audio-cache-v1');
        for (const item of window.lecturesData) {
            const idx = window.lecturesData.indexOf(item);
            const match = await cache.match(item.src);
            const ringBtn = document.getElementById('lectureDlRing_' + idx);
            const statusEl = document.getElementById('lectureDlStatus_' + idx);
            
            if (match && ringBtn) {
                ringBtn.textContent = '✅';
                ringBtn.style.background = 'rgba(76,175,80,0.15)';
                ringBtn.style.borderColor = '#4caf50';
                ringBtn.style.color = '#4caf50';
                if (statusEl && statusEl.textContent === '') {
                    const blob = await match.blob();
                    const sizeMB = (blob.size / (1024 * 1024)).toFixed(1);
                    statusEl.textContent = `✅ محمّل ومحفوظ (${sizeMB} MB)`;
                }
            }
        }
    } catch (e) {}
}

window.startLecturesSleepTimer = function() {
    if (window.lecturesSleepTimeout) clearTimeout(window.lecturesSleepTimeout);
    const minutes = parseInt(document.getElementById('lecturesSleepInput').value) || 20;
    window.lecturesSleepTimeout = setTimeout(() => {
        if (window.currentPlayingLectureAudio) {
            window.currentPlayingLectureAudio.pause();
            if (window.currentPlayingLectureBtn) window.currentPlayingLectureBtn.textContent = '▶';
        }
    }, minutes * 60 * 1000);
    alert(`✅ تم ضبط التايمر على ${minutes} دقيقة`);
};

document.addEventListener('DOMContentLoaded', () => { renderLectures(); });

window.filterLectures = function(category) {
    window.currentLectureFilter = category;
    document.querySelectorAll('.sheikh-tabs .sheikh-btn').forEach(btn => {
        btn.style.background = 'var(--card)';
        btn.style.color = 'var(--text)';
        btn.style.border = '1px solid var(--border)';
    });
    const activeBtn = document.getElementById('lectureCatBtn_' + category);
    if (activeBtn) {
        activeBtn.style.background = 'var(--gold)';
        activeBtn.style.color = '#111';
        activeBtn.style.border = 'none';
    }
    renderLectures();
};

window.downloadSeerahSeries = function() {
    const seerahUrls = window.lecturesData
        .filter(l => l.category === 'السيرة النبوية')
        .map(l => l.src);
    if (typeof downloadBatchWithProgress === 'function') {
        downloadBatchWithProgress(seerahUrls, 'seerahBatchRing');
    }
};

